import fs from "fs";
import { NextRequest, NextResponse } from "next/server";
import { db } from "@/lib/db";
import Tesseract from "tesseract.js";

export const config = {
  api: { bodyParser: false },
};

// Function to process file with OCR.Space API
async function processFileWithOCRSpace(filePath: string) {
  try {
    const base64File = fs.readFileSync(filePath, { encoding: "base64" });

    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 15000); // 15 seconds timeout

    const ocrResponse = await fetch("https://api.ocr.space/parse/image", {
      method: "POST",
      headers: {
        apikey: process.env.OCR_API_KEY || "",
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: new URLSearchParams({
        base64image: `data:application/pdf;base64,${base64File}`,
        isOverlayRequired: "true",
        language: "eng",
      }),
      signal: controller.signal,
    });

    clearTimeout(timeout);
    const result = await ocrResponse.json();

    if (!result || !result.ParsedResults) {
      return { error: "OCR API failed", isMarksheet: false };
    }

    const extractedText = result.ParsedResults[0]?.ParsedText || "";
    const isMarksheet =
      /\b(subjects?|marks?\b(?!.*total)|percentage|grade|score|cgpa|gpa)\b/i.test(
        extractedText
      );

    return { text: extractedText, isMarksheet };
  } catch (error) {
    console.error("Error with OCR.Space API:", error);
    return { error: "OCR API error", isMarksheet: false };
  }
}

// Function to process file with Tesseract.js as fallback
async function processFileWithTesseract(filePath: string) {
  try {
    const { data } = await Tesseract.recognize(filePath, "eng");
    return { text: data.text, isMarksheet: true };
  } catch (error) {
    console.error("Error with Tesseract.js:", error);
    return { error: "Tesseract OCR error", isMarksheet: false };
  }
}

function extractMarks(text: string) {
  if (!text || typeof text !== "string") {
    console.error("OCR text extraction failed or returned null/undefined.");
    return { obtainedMarks: [], totalMarks: 0, percentage: 0 };
  }

  const marksPattern = /\b(\d{2,3})\b/g; // Extracts 2-3 digit numbers
  const marks = [...text.matchAll(marksPattern)].map((match) =>
    parseInt(match[0])
  );

  if (marks.length === 0) {
    console.warn("No marks detected in extracted text:", text);
  }

  const obtainedMarks = marks.filter((m) => m <= 100); // Assume marks are ≤ 100
  const totalMarks = obtainedMarks.length * 100; // Assuming each subject is out of 100

  const sumMarks = obtainedMarks.reduce((acc, val) => acc + val, 0);
  const percentage = totalMarks > 0 ? (sumMarks / totalMarks) * 100 : 0;

  console.log("Extracted Marks:", obtainedMarks, "Total Marks:", totalMarks);

  return { obtainedMarks, totalMarks, percentage };
}


export async function POST(req: NextRequest) {
  try {
    const { email } = await req.json();

    const [user] = await db.query("SELECT * FROM users WHERE email = ?", [
      email,
    ]);

    if (!user.length) {
      return NextResponse.json({ error: "User not found" }, { status: 404 });
    }

    const filePath1 = `./public${user[0].tenth_certificate}`;
    const filePath2 = `./public${user[0].twelfth_certificate}`;

    // First, try OCR.Space API. If it fails, use Tesseract.js
    let result1 = await processFileWithOCRSpace(filePath1);
    if (result1.error) {
      result1 = await processFileWithTesseract(filePath1);
    }

    let result2 = await processFileWithOCRSpace(filePath2);
    if (result2.error) {
      result2 = await processFileWithTesseract(filePath2);
    }

    // Extract marks from OCR text
    const tenthMarks = extractMarks(result1.text);
    const twelfthMarks = extractMarks(result2.text);

    // Eligibility Check (Assuming 35% required for eligibility)
    const isEligible =
      tenthMarks.percentage >= 35 && twelfthMarks.percentage >= 35;

    return NextResponse.json(
      {
        tenth: { ...tenthMarks, isMarksheet: result1.isMarksheet },
        twelfth: { ...twelfthMarks, isMarksheet: result2.isMarksheet },
        eligibility: isEligible ? "Eligible for the program" : "Not eligible",
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("Error processing files:", error);
    return NextResponse.json(
      { error: "Error processing files" },
      { status: 500 }
    );
  }
}
